BEGIN;

CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE TABLE asset_categories (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE NOT NULL, name VARCHAR(120) NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE asset_tags (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE NOT NULL, name VARCHAR(120) NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE assets (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), asset_key VARCHAR(180) UNIQUE NOT NULL, name VARCHAR(180) NOT NULL, category VARCHAR(80) NOT NULL, status VARCHAR(24) NOT NULL CHECK (status IN ('draft','published','archived')), current_version_id UUID, created_by UUID, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE asset_versions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), asset_id UUID NOT NULL REFERENCES assets(id) ON DELETE CASCADE, version INTEGER NOT NULL, storage_key VARCHAR(500) NOT NULL, mime_type VARCHAR(120) NOT NULL, width INTEGER NOT NULL, height INTEGER NOT NULL, size_bytes BIGINT NOT NULL, has_alpha BOOLEAN NOT NULL DEFAULT false, sha256 VARCHAR(64) NOT NULL, metadata JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE(asset_id, version));
ALTER TABLE assets ADD CONSTRAINT assets_current_version_fk FOREIGN KEY (current_version_id) REFERENCES asset_versions(id);
CREATE TABLE asset_tag_links (asset_id UUID NOT NULL REFERENCES assets(id) ON DELETE CASCADE, tag_id UUID NOT NULL REFERENCES asset_tags(id) ON DELETE CASCADE, PRIMARY KEY(asset_id, tag_id));
CREATE TABLE asset_bindings (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), asset_id UUID NOT NULL REFERENCES assets(id), scope_type VARCHAR(32) NOT NULL, scope_id UUID, slot_key VARCHAR(180) NOT NULL, priority INTEGER NOT NULL DEFAULT 0, starts_at TIMESTAMPTZ, ends_at TIMESTAMPTZ, enabled BOOLEAN NOT NULL DEFAULT true, metadata JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX asset_bindings_lookup ON asset_bindings(slot_key, scope_type, scope_id, enabled, priority DESC);
CREATE TABLE page_backgrounds (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), page_key VARCHAR(80) UNIQUE NOT NULL, light_asset_id UUID REFERENCES assets(id), dark_asset_id UUID REFERENCES assets(id), mobile_asset_id UUID REFERENCES assets(id), dark_mobile_asset_id UUID REFERENCES assets(id), fit VARCHAR(20) NOT NULL DEFAULT 'cover', position VARCHAR(80) NOT NULL DEFAULT 'center', focal_point JSONB NOT NULL DEFAULT '{"x":50,"y":50}', overlay_color VARCHAR(20) NOT NULL DEFAULT '#F7FAFF', overlay_opacity NUMERIC(4,3) NOT NULL DEFAULT .7, asset_opacity NUMERIC(4,3) NOT NULL DEFAULT .08, blur INTEGER NOT NULL DEFAULT 0, status VARCHAR(24) NOT NULL DEFAULT 'draft', scheduled_at TIMESTAMPTZ, version INTEGER NOT NULL DEFAULT 1, updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE visual_review_runs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), asset_version_id UUID REFERENCES asset_versions(id), page_key VARCHAR(80) NOT NULL, viewport VARCHAR(40) NOT NULL, screenshot_key VARCHAR(500), result VARCHAR(24) NOT NULL, issue_types TEXT[] NOT NULL DEFAULT '{}', reviewed_by UUID, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE challenge_instances (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id UUID NOT NULL, owner_type VARCHAR(24) NOT NULL, owner_id UUID NOT NULL, status VARCHAR(24) NOT NULL, runtime_type VARCHAR(24) NOT NULL, runtime_id VARCHAR(255), access_url VARCHAR(500), port INTEGER, started_at TIMESTAMPTZ, expires_at TIMESTAMPTZ, operation_version INTEGER NOT NULL DEFAULT 0, last_error TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE UNIQUE INDEX challenge_instances_active_owner ON challenge_instances(challenge_id, owner_type, owner_id) WHERE status NOT IN ('stopped','expired');
CREATE TABLE instance_operations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), instance_id UUID NOT NULL REFERENCES challenge_instances(id), operation VARCHAR(24) NOT NULL CHECK (operation IN ('start','restart','stop','reset')), requested_by UUID NOT NULL, idempotency_key VARCHAR(180) NOT NULL, from_status VARCHAR(24) NOT NULL, to_status VARCHAR(24) NOT NULL, result VARCHAR(24) NOT NULL, error_message TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), finished_at TIMESTAMPTZ, UNIQUE(requested_by, idempotency_key));
CREATE TABLE asset_audit_logs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), actor_id UUID, action VARCHAR(80) NOT NULL, target_type VARCHAR(80) NOT NULL, target_id UUID, before_data JSONB, after_data JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now());

COMMIT;
